```(function() {
    const parseTimeToMinutes = (timeStr) =&gt; {
        if (!timeStr) return 0;
        const match = timeStr.match(/(오전|오후)\s+(\d+):(\d+)/);
        if (!match) return 0;

        let [_, period, hours, minutes] = match;
        hours = parseInt(hours);
        minutes = parseInt(minutes);

        if (period === '오후' &amp;&amp; hours !== 12) hours += 12;
        if (period === '오전' &amp;&amp; hours === 12) hours = 0;

        return hours * 60 + minutes;
    };

    const daySections = document.querySelectorAll('section.c-iomxRD');
    let totalOfficeMin = 0;
    let totalRemoteMin = 0;

    daySections.forEach(section =&gt; {
        // 1. 해당 섹션의 시간 기록들 추출 (오전/오후 00:00 형태만)
        const timeElements = Array.from(section.querySelectorAll('.c-dlCFbj'))
            .filter(el =&gt; el.textContent.includes(':'));

        if (timeElements.length &lt; 2) return;

        const timeMinutes = timeElements.map(el =&gt; parseTimeToMinutes(el.textContent.trim()));

        // 2. 시간 간격 계산 (예: [출근, 휴게시작, 휴게종료, 퇴근] -&gt; (휴게시작-출근) + (퇴근-휴게종료))
        let dayNetWorkMin = 0;
        for (let i = 0; i &lt; timeMinutes.length - 1; i += 2) {
            let start = timeMinutes[i];
            let end = timeMinutes[i + 1];

            // 종료가 시작보다 빠르면 자정 넘긴 것으로 처리
            if (end &lt; start) end += 24 * 60;

            dayNetWorkMin += (end - start);
        }

        // 3. 근무 유형 판별
        const isOffice = !!section.querySelector('.c-iyXem-FxjDs-color-cyan');
        const isRemote = !!section.querySelector('.c-iyXem-eogrnF-color-yellow');

        if (isOffice) {
            totalOfficeMin += dayNetWorkMin;
        } else if (isRemote) {
            totalRemoteMin += dayNetWorkMin;
        }
    });

    const toHours = (min) =&gt; (min / 60).toFixed(2);

    console.log("%c [Flex 근무 시간 최종 정산] ", "background: #222; color: #fff; font-size: 14px; padding: 5px;");
    console.log(`일반 근무 (사무실): %c${toHours(totalOfficeMin)} 시간`, "color: #00d4ff; font-weight: bold;");
    console.log(`원격 근무 (재택): %c${toHours(totalRemoteMin)} 시간`, "color: #ffca00; font-weight: bold;");
    console.log(`%c총 순 근무 시간: ${toHours(totalOfficeMin + totalRemoteMin)} 시간`, "border-top: 1px solid #ccc; font-weight: bold;");
})();```
